mapper.select:
SELECT board_no, comment_no, content, commenter, reg_date
FROM BOARD_COMMENT
WHERE comment_no = #{commentNo}

mapper.update:
UPDATE BOARD_COMMENT
SET content =#{content}
WHERE comment_no = #{commentNo}

mapper.delete:
DELETE FROM BOARD_COMMENT
WHERE comment_no = #{commentNo} 
AND commenter = #{commenter}
